/// and returns a `TaskIterator` for customization before execution.
///
/// Use this function when you need to:
/// - Wrap the task with custom valtron combinators
/// - Compose multiple tasks before execution
/// - Intercept task execution for logging or testing
///
/// For direct execution, use `accesscontextmanager_services_list_execute()` or `accesscontextmanager_services_list`.
///
/// # Arguments
///
/// * `builder` - A `ClientRequestBuilder`, typically from `accesscontextmanager_services_list_builder()`
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn accesscontextmanager_services_list_task(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl TaskIterator<
            D = Result<ApiResponse<ListSupportedServicesResponse>, ApiError>,
            P = ApiPending,
        > + Send
        + 'static,
    ApiError,
> {
    Ok(builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success {
                stream,
                intro,
                headers,
                ..
            } => {
                let status_code: usize = intro.0.into();

                if status_code < 200 || status_code >= 300 {
                    // Capture body for error parsing
                    let body = body_reader::collect_string(stream);
                    // Try to parse as structured API error
                    if let Ok(error_body) = serde_json::from_str::<ApiErrorBody>(&body) {
                        return Err(ApiError::ApiError(error_body.error));
                    }
                    // Fall back to raw HTTP status error
                    return Err(ApiError::HttpStatus {
                        code: status_code as u16,
                        headers: headers.clone(),
                        body: Some(body),
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: ListSupportedServicesResponse = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status_code as u16,
                    headers: headers.clone(),
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending))
}

